export const PopperActionEnum = {
  click: 'click',
  contextMenu: 'contextMenu',
  hover: 'hover',
  focus: 'focus',
  blur: 'blur',
  mouseEnter: 'mouseEnter',
  mouseLeave: 'mouseLeave',
} as const;

const KEYDOWN_ESC_FLAG = Symbol.for('keydown.esc.flag');

